(window.webpackJsonp=window.webpackJsonp||[]).push([[260],{1515:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">edges</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">M</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">N</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> reachableNodes = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">edges, M, N</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> graph=<span class=\\"hljs-built_in\\">Array</span>(N).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span>[])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [v,w,dis] <span class=\\"hljs-keyword\\">of</span> edges){\\n    graph[v].push([w,dis+<span class=\\"hljs-number\\">1</span>])\\n    graph[w].push([v,dis+<span class=\\"hljs-number\\">1</span>])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> minDist=<span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-literal\\">Infinity</span>)\\n  minDist[<span class=\\"hljs-number\\">0</span>]=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> arr=[<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> v=arr.shift()\\n      <span class=\\"hljs-keyword\\">let</span> adj=graph[v]\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [w,dis] <span class=\\"hljs-keyword\\">of</span> adj){\\n        <span class=\\"hljs-keyword\\">if</span>(minDist[w]&gt;minDist[v]+dis){\\n          minDist[w]=minDist[v]+dis\\n          arr.push(w)\\n        }\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> result=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [v,w,dis] <span class=\\"hljs-keyword\\">of</span> edges){\\n    <span class=\\"hljs-keyword\\">let</span> left=<span class=\\"hljs-built_in\\">Math</span>.min(<span class=\\"hljs-built_in\\">Math</span>.max(M-minDist[v],<span class=\\"hljs-number\\">0</span>),dis),\\n        right=<span class=\\"hljs-built_in\\">Math</span>.min(<span class=\\"hljs-built_in\\">Math</span>.max(M-minDist[w],<span class=\\"hljs-number\\">0</span>),dis)\\n    result+=<span class=\\"hljs-built_in\\">Math</span>.min(left+right,dis)\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> dis <span class=\\"hljs-keyword\\">of</span> minDist){\\n    <span class=\\"hljs-keyword\\">if</span>(M&gt;=dis)result++\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> result \\n};\\n</code></pre>\\n"],"titleSlug":"reachable-nodes-in-subdivided-graph","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u9996\u5148\u6784\u5efa<code>graph</code>\uff0c\u7136\u540e\u6784\u5efa<code>minDis</code>\uff0c\u6307\u7684\u662f\u4ece<code>0</code>\u5230\u5176\u4ed6\u6240\u6709\u70b9\u7684<strong>\u6700\u77ed</strong>\u8ddd\u79bb\uff0c\u8ba1\u7b97<code>minDis</code>\u53ef\u4ee5\u4f7f\u7528<code>Dijkstra</code>\u7b97\u6cd5\u3002</p>\\n<p>\u5f53\u7b97\u51fa\u6240\u6709\u6700\u77ed\u8ddd\u79bb\u540e\uff0c\u8981\u8ba1\u7b97\u67d0\u4e00\u6761\u8fb9\u4e0a\u7684\u70b9\u54ea\u4e9b\u80fd\u901a\u8fc7\uff0c\u800c\u4e00\u6761\u8fb9\u6709\u4e24\u4e2a\u9876\u70b9<code>v</code>\u548c<code>w</code>\uff1b</p>\\n<p>\u56e0\u6b64\u53ef\u4ee5\u8ba1\u7b97\u51fa\u8fd9\u6761\u8fb9\u88ab\u8d70\u8fc7\u7684\u8ddd\u79bb\u5c31\u662f<code>\u5230v\u7684\u6700\u77ed\u8ddd\u79bb\u540e\u8fd8\u5269\u4e0b\u7684\u6b65\u6570 + \u5230w\u6700\u77ed\u8ddd\u79bb\u540e\u8fd8\u5269\u4e0b\u7684\u6b65\u6570</code>\uff0c\u5f53\u7136\u8fd9\u4e2a\u6570\u4e0d\u80fd\u8d85\u8fc7\u8fd9\u6761\u8fb9\u7684\u957f\u5ea6\u3002</p>\\n<p>\u6700\u540e\uff0c\u5728\u8ba1\u7b97\u54ea\u4e9b\u9876\u70b9\u662f\u53ef\u4ee5\u901a\u8fc7\u7684\uff0c\u53ea\u8981<code>\u5230\u5f53\u524d\u9876\u70b9\u7684\u6700\u77ed\u8ddd\u79bb&lt;=M</code>\uff0c\u5c31\u662f\u53ef\u4ee5\u901a\u8fc7\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u65e0\u5411\u56fe\uff08<strong>\u539f\u59cb\u56fe</strong>\uff09\uff0c\u56fe\u4e2d\u6709 <code>n</code> \u4e2a\u8282\u70b9\uff0c\u7f16\u53f7\u4ece <code>0</code> \u5230 <code>n - 1</code> \u3002\u4f60\u51b3\u5b9a\u5c06\u56fe\u4e2d\u7684\u6bcf\u6761\u8fb9\u7ec6\u5206\u4e3a\u4e00\u6761\u8282\u70b9\u94fe\uff0c\u6bcf\u6761\u8fb9\u4e4b\u95f4\u7684\u65b0\u8282\u70b9\u6570\u5404\u4e0d\u76f8\u540c\u3002</p>\\n\\n<p>\u56fe\u7528\u7531\u8fb9\u7ec4\u6210\u7684\u4e8c\u7ef4\u6570\u7ec4 <code>edges</code> \u8868\u793a\uff0c\u5176\u4e2d\xa0<code>edges[i] = [u<sub>i</sub>, v<sub>i</sub>, cnt<sub>i</sub>]</code> \u8868\u793a\u539f\u59cb\u56fe\u4e2d\u8282\u70b9\xa0<code>u<sub>i</sub></code> \u548c\xa0<code>v<sub>i</sub></code> \u4e4b\u95f4\u5b58\u5728\u4e00\u6761\u8fb9\uff0c<code>cnt<sub>i</sub></code> \u662f\u5c06\u8fb9\u7ec6\u5206\u540e\u7684\u65b0\u8282\u70b9\u603b\u6570\u3002\u6ce8\u610f\uff0c<code>cnt<sub>i</sub> == 0</code> \u8868\u793a\u8fb9\u4e0d\u53ef\u7ec6\u5206\u3002</p>\\n\\n<p>\u8981\u7ec6\u5206\u8fb9 <code>[ui, vi]</code> \uff0c\u9700\u8981\u5c06\u5176\u66ff\u6362\u4e3a <code>(cnt<sub>i</sub> + 1)</code> \u6761\u65b0\u8fb9\uff0c\u548c\xa0<code>cnt<sub>i</sub></code> \u4e2a\u65b0\u8282\u70b9\u3002\u65b0\u8282\u70b9\u4e3a <code>x<sub>1</sub></code>, <code>x<sub>2</sub></code>, ..., <code>x<sub>cnt<sub>i</sub></sub></code> \uff0c\u65b0\u8fb9\u4e3a <code>[u<sub>i</sub>, x<sub>1</sub>]</code>, <code>[x<sub>1</sub>, x<sub>2</sub>]</code>, <code>[x<sub>2</sub>, x<sub>3</sub>]</code>, ..., <code>[x<sub>cnt<sub>i</sub>+1</sub>, x<sub>cnt<sub>i</sub></sub>]</code>, <code>[x<sub>cnt<sub>i</sub></sub>, v<sub>i</sub>]</code> \u3002</p>\\n\\n<p class=\\"MachineTrans-lang-zh-CN\\">\u73b0\u5728\u5f97\u5230\u4e00\u4e2a\u65b0\u7684 <strong>\u7ec6\u5206\u56fe</strong> \uff0c\u8bf7\u4f60\u8ba1\u7b97\u4ece\u8282\u70b9 <code>0</code> \u51fa\u53d1\uff0c\u53ef\u4ee5\u5230\u8fbe\u591a\u5c11\u4e2a\u8282\u70b9\uff1f\u8282\u70b9 <strong>\u662f\u5426\u53ef\u4ee5\u5230\u8fbe\u7684\u5224\u65ad\u6761\u4ef6</strong> \u4e3a\uff1a\u5982\u679c\u8282\u70b9\u95f4\u8ddd\u79bb\u662f <code>maxMoves</code> \u6216\u66f4\u5c11\uff0c\u5219\u89c6\u4e3a\u53ef\u4ee5\u5230\u8fbe\uff1b\u5426\u5219\uff0c\u4e0d\u53ef\u5230\u8fbe\u3002</p>\\n\\n<p class=\\"MachineTrans-lang-zh-CN\\">\u7ed9\u4f60\u539f\u59cb\u56fe\u548c <code>maxMoves</code> \uff0c\u8fd4\u56de\u65b0\u7684\u7ec6\u5206\u56fe\u4e2d\u4ece\u8282\u70b9 <code>0</code> \u51fa\u53d1<strong> \u53ef\u5230\u8fbe\u7684\u8282\u70b9\u6570 </strong>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://s3-lc-upload.s3.amazonaws.com/uploads/2018/08/01/origfinal.png\\" style=\\"width: 600px; height: 247px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>edges = [[0,1,10],[0,2,1],[1,2,2]], maxMoves = 6, n = 3\\n<strong>\u8f93\u51fa\uff1a</strong>13\\n<strong>\u89e3\u91ca\uff1a</strong>\u8fb9\u7684\u7ec6\u5206\u60c5\u51b5\u5982\u4e0a\u56fe\u6240\u793a\u3002\\n\u53ef\u4ee5\u5230\u8fbe\u7684\u8282\u70b9\u5df2\u7ecf\u7528\u9ec4\u8272\u6807\u6ce8\u51fa\u6765\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>edges = [[0,1,4],[1,2,6],[0,2,8],[1,3,1]], maxMoves = 10, n = 4\\n<strong>\u8f93\u51fa\uff1a</strong>23\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>edges = [[1,2,4],[1,4,5],[1,3,1],[2,3,4],[3,4,5]], maxMoves = 17, n = 5\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u8282\u70b9 0 \u4e0e\u56fe\u7684\u5176\u4f59\u90e8\u5206\u6ca1\u6709\u8fde\u901a\uff0c\u6240\u4ee5\u53ea\u6709\u8282\u70b9 0 \u53ef\u4ee5\u5230\u8fbe\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= edges.length <= min(n * (n - 1) / 2, 10<sup>4</sup>)</code></li>\\n\\t<li><code>edges[i].length == 3</code></li>\\n\\t<li><code>0 <= u<sub>i</sub> < v<sub>i</sub> < n</code></li>\\n\\t<li>\u56fe\u4e2d <strong>\u4e0d\u5b58\u5728\u5e73\u884c\u8fb9</strong></li>\\n\\t<li><code>0 <= cnt<sub>i</sub> <= 10<sup>4</sup></code></li>\\n\\t<li><code>0 <= maxMoves <= 10<sup>9</sup></code></li>\\n\\t<li><code>1 <= n <= 3000</code></li>\\n</ul>\\n","title":"882. \u7ec6\u5206\u56fe\u4e2d\u7684\u53ef\u5230\u8fbe\u7ed3\u70b9","relatedTags":["\u5806","\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Hard","lang":["javascript"],"uniqueID":"882"}')}}]);